import React from 'react'
import styled from 'styled-components'
import googleIcon from './static/googleIcon.jpg'
import {useSelector, useDispatch} from 'react-redux'
import {accountSelector} from '../redux/accountSlice'

const GoogleSignIn = styled.a `
width:100%;
height:40px;
font-weight:bold;
font-size:1rem;
border:1px solid #1C1C1C;
border-radius:8px;
display:flex;
align-items:center;
text-decoration:none;
color:#1C1C1C;
`

const GoogleIcon = styled.div `
position:absolute;
background-image:url(${googleIcon});
width:20px;
height:20px;
background-size:cover;
background-position:center;
margin-left:10px;
`

const Div = styled.div `
margin:0 auto;
`
const googleAPIAddress = 'https://accounts.google.com/o/oauth2/v2/auth/oauthchooseaccount?access_type=offline&scope=https%3A%2F%2Fwww.googleapis.com%2Fauth%2Fuserinfo.email%20https%3A%2F%2Fwww.googleapis.com%2Fauth%2Fuserinfo.profile&response_type=code&client_id=567926913321-oofmqdtjvc13bvnlsviubhdrpkuma4vm.apps.googleusercontent.com&redirect_uri=http%3A%2F%2Flocalhost%3A5001%2FOauth2%2Fgoogle&service=lso&flowName=GeneralOAuthFlow'

export default function GoogleLoginBtn () {

	return (
		<GoogleSignIn href={googleAPIAddress}>
			<GoogleIcon></GoogleIcon>
			<Div>Continue with Google</Div>
		</GoogleSignIn>
	)
}
